mapper.select:
SELECT r.role_name AS roleName
FROM tb_user u JOIN tb_role r ON JSON_CONTAINS(u.roles, CAST(r.id AS CHAR))
WHERE u.id = #{userId}

SELECT id, role_name AS roleName, remark, systemic, status, 0 AS userCount, (CASE WHEN permissions IS NOT NULL THEN JSON_LENGTH(permissions) ELSE 0 END) AS permissions FROM tb_role
role_name LIKE CONCAT("%",#{roleName},"%")
AND status = #{status}
ORDER BY id LIMIT #{start},#{size}

SELECT COUNT(*) FROM tb_role
role_name LIKE CONCAT("%",#{roleName},"%")
AND status = #{status}

SELECT EXISTS(
    SELECT 1
    FROM tb_role
    WHERE role_name = #{roleName}

        AND id != #{id}

)

mapper.update:
UPDATE tb_role
SET role_name=#{roleName},
    remark=#{remark},
    status=#{status},
    permissions=#{permissions}
WHERE id = #{id}

